import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { Fragment, forwardRef, type ComponentRef, type Key, type ReactNode } from 'react';
import { ChevronRightIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Breadcrumbs.module.css';

type BreadcrumbsPathItem = {
  href?: string;
  key?: Key;
  label: ReactNode;
};
type BreadcrumbsPathProps = Omit<HTMLArkProps<'ol'>, 'children'> & {
  items: readonly BreadcrumbsPathItem[];
  separator?: ReactNode;
};

const BreadcrumbsRoot = forwardRef<ComponentRef<typeof ark.nav>, HTMLArkProps<'nav'>>(
  function BreadcrumbsRoot({ className, 'aria-label': ariaLabel = 'Breadcrumb', ...props }, ref) {
    return (
      <ark.nav
        ref={ref}
        data-scope="breadcrumbs"
        data-part="root"
        data-slot="breadcrumbs-root"
        aria-label={ariaLabel}
        className={clsx(styles.root, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const BreadcrumbsList = forwardRef<ComponentRef<typeof ark.ol>, HTMLArkProps<'ol'>>(
  function BreadcrumbsList({ className, ...props }, ref) {
    return (
      <ark.ol
        ref={ref}
        data-scope="breadcrumbs"
        data-part="list"
        data-slot="breadcrumbs-list"
        className={clsx(styles.list, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const BreadcrumbsItem = forwardRef<ComponentRef<typeof ark.li>, HTMLArkProps<'li'>>(
  function BreadcrumbsItem({ className, ...props }, ref) {
    return (
      <ark.li
        ref={ref}
        data-scope="breadcrumbs"
        data-part="item"
        data-slot="breadcrumbs-item"
        className={clsx(styles.item, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const BreadcrumbsLink = forwardRef<ComponentRef<typeof ark.a>, HTMLArkProps<'a'>>(
  function BreadcrumbsLink({ className, ...props }, ref) {
    return (
      <ark.a
        ref={ref}
        data-scope="breadcrumbs"
        data-part="link"
        data-slot="breadcrumbs-link"
        className={clsx(styles.link, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const BreadcrumbsPage = forwardRef<ComponentRef<typeof ark.span>, HTMLArkProps<'span'>>(
  function BreadcrumbsPage({ className, ...props }, ref) {
    return (
      <ark.span
        ref={ref}
        data-scope="breadcrumbs"
        data-part="page"
        data-slot="breadcrumbs-page"
        aria-current="page"
        className={clsx(styles.page, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

function BreadcrumbsPath({ items, separator, ...props }: BreadcrumbsPathProps) {
  return (
    <BreadcrumbsList {...props}>
      {items.map((item, index) => {
        const isLastItem = index === items.length - 1;

        return (
          <Fragment key={item.key ?? item.href ?? index}>
            <BreadcrumbsItem>
              {item.href && !isLastItem ? (
                <BreadcrumbsLink href={item.href}>{item.label}</BreadcrumbsLink>
              ) : (
                <BreadcrumbsPage>{item.label}</BreadcrumbsPage>
              )}
            </BreadcrumbsItem>
            {!isLastItem ? <BreadcrumbsSeparator>{separator}</BreadcrumbsSeparator> : null}
          </Fragment>
        );
      })}
    </BreadcrumbsList>
  );
}

const BreadcrumbsSeparator = forwardRef<ComponentRef<typeof ark.li>, HTMLArkProps<'li'>>(
  function BreadcrumbsSeparator({ className, children, role = 'presentation', ...props }, ref) {
    return (
      <ark.li
        ref={ref}
        data-scope="breadcrumbs"
        data-part="separator"
        data-slot="breadcrumbs-separator"
        aria-hidden="true"
        role={role}
        className={clsx(styles.separator, normalizeClassName(className))}
        {...props}
      >
        {children ?? <ChevronRightIcon className={styles.separatorIcon} />}
      </ark.li>
    );
  },
);

const BreadcrumbsEllipsis = forwardRef<ComponentRef<typeof ark.span>, HTMLArkProps<'span'>>(
  function BreadcrumbsEllipsis({ className, children = '...', ...props }, ref) {
    return (
      <ark.span
        ref={ref}
        data-scope="breadcrumbs"
        data-part="ellipsis"
        data-slot="breadcrumbs-ellipsis"
        aria-hidden="true"
        className={clsx(styles.ellipsis, normalizeClassName(className))}
        {...props}
      >
        {children}
      </ark.span>
    );
  },
);

const Breadcrumbs = Object.assign(BreadcrumbsRoot, {
  Root: BreadcrumbsRoot,
  List: BreadcrumbsList,
  Item: BreadcrumbsItem,
  Link: BreadcrumbsLink,
  Path: BreadcrumbsPath,
  Page: BreadcrumbsPage,
  Separator: BreadcrumbsSeparator,
  Ellipsis: BreadcrumbsEllipsis,
});

export { Breadcrumbs };

@layer moduix.components {
  .root[data-scope='breadcrumbs'][data-part='root'] {
    max-width: var(--moduix-breadcrumbs-max-width, 100%);
    color: var(--moduix-breadcrumbs-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-breadcrumbs-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-breadcrumbs-line-height, var(--moduix-line-height-text-sm));
  }

  .list[data-scope='breadcrumbs'][data-part='list'] {
    display: flex;
    min-width: 0;
    align-items: center;
    gap: var(--moduix-breadcrumbs-gap, var(--moduix-spacing-1));
    margin: 0;
    padding: 0;
    list-style: none;
    white-space: nowrap;

    > .item:last-child {
      flex: 1 1 auto;
      max-width: var(--moduix-breadcrumbs-item-max-width, 16rem);
    }
  }

  .item[data-scope='breadcrumbs'][data-part='item'] {
    display: inline-flex;
    min-width: 0;
    flex: 0 1 auto;
    align-items: center;
  }

  .link[data-scope='breadcrumbs'][data-part='link'],
  .page[data-scope='breadcrumbs'][data-part='page'] {
    display: block;
    min-width: 0;
    max-width: 100%;
    padding-inline: var(--moduix-breadcrumbs-item-padding-x, var(--moduix-spacing-1));
    white-space: nowrap;
  }

  .link[data-scope='breadcrumbs'][data-part='link'],
  .page[data-scope='breadcrumbs'][data-part='page'],
  .ellipsis[data-scope='breadcrumbs'][data-part='ellipsis'] {
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .link[data-scope='breadcrumbs'][data-part='link'] {
    color: var(--moduix-breadcrumbs-link-color, var(--moduix-color-muted-foreground));
    text-decoration: var(--moduix-breadcrumbs-link-text-decoration, none);
    text-underline-offset: var(--moduix-breadcrumbs-link-underline-offset, 0.2em);
    border-radius: var(--moduix-breadcrumbs-link-radius, var(--moduix-radius-sm));
    outline: none;
    transition: var(--moduix-breadcrumbs-link-transition, var(--moduix-transition-default));

    @media (hover: hover) {
      &:hover {
        color: var(--moduix-breadcrumbs-link-color-hover, var(--moduix-color-foreground));
        text-decoration: var(--moduix-breadcrumbs-link-text-decoration-hover, none);
      }
    }

    &:focus-visible {
      box-shadow: 0 0 0
        var(
          --moduix-breadcrumbs-focus-ring-width,
          var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
        )
        var(--moduix-breadcrumbs-focus-ring-color, var(--moduix-color-ring));
    }
  }

  .page[data-scope='breadcrumbs'][data-part='page'] {
    color: var(--moduix-breadcrumbs-page-color, var(--moduix-color-foreground));
    font-weight: var(--moduix-breadcrumbs-page-font-weight, var(--moduix-weight-medium));
  }

  .separator[data-scope='breadcrumbs'][data-part='separator'] {
    display: inline-flex;
    align-items: center;
    color: var(--moduix-breadcrumbs-separator-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-breadcrumbs-separator-font-size, 0.875em);
    line-height: 1;
    user-select: none;
  }

  .separatorIcon {
    width: var(--moduix-breadcrumbs-separator-icon-size, 1em);
    height: var(--moduix-breadcrumbs-separator-icon-size, 1em);
    flex: none;
  }

  .ellipsis[data-scope='breadcrumbs'][data-part='ellipsis'] {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: var(--moduix-breadcrumbs-ellipsis-size, var(--moduix-spacing-4));
    min-height: var(--moduix-breadcrumbs-ellipsis-size, var(--moduix-spacing-4));
    padding-inline: var(--moduix-breadcrumbs-item-padding-x, var(--moduix-spacing-1));
    color: var(--moduix-breadcrumbs-ellipsis-color, var(--moduix-color-muted-foreground));
    border-radius: var(--moduix-breadcrumbs-ellipsis-radius, var(--moduix-radius-sm));
  }
}
